var data = ($.steps.scrapeWebsite.response && $.steps.scrapeWebsite.response.data) ? $.steps.scrapeWebsite.response.data : {};
var markdown = (data.markdown || '').slice(0, 6000);
var links = data.links || [];
var linkList = links.slice(0, 30).map(function(l) {
  if (typeof l === 'string') return l;
  return (l.text || l.title || '') + ' -> ' + (l.href || l.url || '');
}).join('\n');
return { markdown: markdown, linkList: linkList, linkCount: links.length };

var ctx = $.steps.extractContent.output;
var prompt = 'You are a content curator AI. Analyze the following scraped website content and extract all identifiable articles, blog posts, news items, or updates.

WEBSITE: ' + $.input.websiteUrl + '
FEED TITLE: ' + ($.input.feedTitle || 'Website Feed') + '

SCRAPED CONTENT:
' + ctx.markdown + '

LINKS FOUND (' + ctx.linkCount + ' total):
' + ctx.linkList + '

Extract each article/update with its title, URL (if found), date (if found), and a brief summary. Return ONLY valid JSON:
{
  "feedTitle": "...",
  "articles": [
    { "title": "...", "url": "...", "date": "...", "summary": "..." }
  ],
  "totalFound": 0
}';
return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var blocks = [];
var feedTitle = ai.feedTitle || $.input.feedTitle || 'Website Feed';
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':newspaper: ' + feedTitle, emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Source:* <' + $.input.websiteUrl + '> | *Articles found:* ' + (ai.totalFound || (ai.articles || []).length) } });
blocks.push({ type: 'divider' });
var articles = ai.articles || [];
articles.slice(0, 10).forEach(function(a, i) {
  var titleText = a.url ? '<' + a.url + '|' + a.title + '>' : '*' + a.title + '*';
  var meta = '';
  if (a.date) meta = ':clock1: ' + a.date + '\n';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (i + 1) + '.* ' + titleText + '\n' + meta + a.summary } });
});
if (articles.length > 10) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '_...and ' + (articles.length - 10) + ' more articles_' } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':robot_face: Generated by Firecrawl + Claude AI via One CLI' }] });
var fallback = feedTitle + ': ' + articles.length + ' articles extracted from ' + $.input.websiteUrl;
if (ai.text) fallback = ai.text.slice(0, 500);
return { blocks, fallback };
